 17→package org.apache.kafka.streams.processor.internals.tasks;
 18→
 19→import org.apache.kafka.common.KafkaFuture;
 20→import org.apache.kafka.common.internals.KafkaFutureImpl;
 21→import org.apache.kafka.common.utils.LogContext;
 22→import org.apache.kafka.common.utils.Time;
 23→import org.apache.kafka.streams.errors.StreamsException;
 24→import org.apache.kafka.streams.processor.TaskId;
 25→import org.apache.kafka.streams.processor.internals.ReadOnlyTask;
 26→import org.apache.kafka.streams.processor.internals.StreamTask;
 27→import org.apache.kafka.streams.processor.internals.Task;
 28→import org.apache.kafka.streams.processor.internals.TaskExecutionMetadata;
 29→import org.apache.kafka.streams.processor.internals.TasksRegistry;
 30→
 31→import org.slf4j.Logger;
 32→
 33→import java.time.Duration;
 34→import java.util.ArrayList;
 35→import java.util.HashMap;
 36→import java.util.List;
 37→import java.util.Map;
 38→import java.util.Set;
 39→import java.util.concurrent.ConcurrentSkipListSet;
 40→import java.util.concurrent.locks.Condition;
 41→import java.util.concurrent.locks.Lock;
 42→import java.util.concurrent.locks.ReentrantLock;
 43→import java.util.function.Supplier;
 44→import java.util.stream.Collectors;
 45→
 46→/**
 47→ * An active task could only be in one of the following status:
 48→ *
 49→ * 1. It's assigned to one of the executors for processing.
 50→ * 2. It's locked for committing, removal, other manipulations etc.
 51→ * 3. Neither 1 or 2, i.e. it stays idle. This is possible if we do not have enough executors or because those tasks
 52→ *    are not processable (e.g. because no records fetched) yet.
 53→ */
 54→public final class DefaultTaskManager implements TaskManager {
 55→
 56→    private final Time time;
 57→    private final Logger log;
 58→    private final TasksRegistry tasks;
 59→
 60→    private final Lock tasksLock = new ReentrantLock();
 61→    private final Condition tasksCondition = tasksLock.newCondition();
 62→    private final List<TaskId> lockedTasks = new ArrayList<>();
 63→    private final Map<TaskId, StreamsException> uncaughtExceptions = new HashMap<>();
 64→    private final Map<TaskId, TaskExecutor> assignedTasks = new HashMap<>();
 65→    private final TaskExecutionMetadata taskExecutionMetadata;
 66→
 67→    private final List<TaskExecutor> taskExecutors;
 68→
 69→    public static class DefaultTaskExecutorCreator implements TaskExecutorCreator {
 70→        @Override
 71→        public TaskExecutor create(final TaskManager taskManager, final String name, final Time time, final TaskExecutionMetadata taskExecutionMetadata) {
 72→            return new DefaultTaskExecutor(taskManager, name, time, taskExecutionMetadata);
 73→        }
 74→    }
 75→
 76→    public DefaultTaskManager(final Time time,
 77→                              final String clientId,
 78→                              final TasksRegistry tasks,
 79→                              final TaskExecutorCreator executorCreator,
 80→                              final TaskExecutionMetadata taskExecutionMetadata,
 81→                              final int numExecutors
 82→                              ) {
 83→        final String logPrefix = String.format("%s ", clientId);
 84→        final LogContext logContext = new LogContext(logPrefix);
 85→        this.log = logContext.logger(DefaultTaskManager.class);
 86→        this.time = time;
 87→        this.tasks = tasks;
 88→        this.taskExecutionMetadata = taskExecutionMetadata;
 89→
 90→        this.taskExecutors = new ArrayList<>(numExecutors);
 91→        for (int i = 1; i <= numExecutors; i++) {
 92→            final String name = clientId + "-TaskExecutor-" + i;
 93→            this.taskExecutors.add(executorCreator.create(this, name, time, taskExecutionMetadata));
 94→        }
 95→    }
 96→
 97→    @Override
 98→    public StreamTask assignNextTask(final TaskExecutor executor) {
 99→        return returnWithTasksLocked(() -> {
100→            if (!taskExecutors.contains(executor)) {
101→                throw new IllegalArgumentException("The requested executor for getting next task to assign is unrecognized");
102→            }
103→
104→            // the most naive scheduling algorithm for now: give the next unlocked, unassigned, and  processable task
105→            for (final StreamTask task : tasks.activeInitializedTasks()) {
106→                if (!assignedTasks.containsKey(task.id()) &&
107→                    !lockedTasks.contains(task.id()) &&
108→                    canProgress(task, time.milliseconds()) &&
109→                    !hasUncaughtException(task.id())
110→                ) {
111→
112→                    assignedTasks.put(task.id(), executor);
113→
114→                    log.debug("Assigned task {} to executor {}", task.id(), executor.name());
115→
116→                    return task;
117→                }
118→            }
119→
120→            log.debug("Found no assignable task for executor {}", executor.name());
121→
122→            return null;
123→        });
124→    }
125→
126→    @Override
127→    public void awaitProcessableTasks(final Supplier<Boolean> isShuttingDown) throws InterruptedException {
128→        final boolean interrupted = returnWithTasksLocked(() -> {
129→            for (final StreamTask task : tasks.activeInitializedTasks()) {
130→                if (!assignedTasks.containsKey(task.id()) &&
131→                    !lockedTasks.contains(task.id()) &&
132→                    canProgress(task, time.milliseconds()) &&
133→                    !hasUncaughtException(task.id())
134→                ) {
135→                    log.debug("Await unblocked: returning early from await since a processable task {} was found", task.id());
136→                    return false;
137→                }
138→            }
139→            try {
140→                // We re-check the shutdownRequest atomic boolean to avoid a race condition. If this thread was
141→                // previously interrupted while awaiting tasksCondition, it is possible to miss the signalAll that
142→                // is called during shutdown. If this happens, we end up blocking in the await forever.
143→                if (!isShuttingDown.get()) {
144→                    log.debug("Await blocking");
145→                    tasksCondition.await();
146→                } else {
147→                    log.debug("Not awaiting since shutdown was requested");
148→                }
149→            } catch (final InterruptedException ignored) {
150→                // we interrupt the thread for shut down and pause.
151→                // we can ignore this exception.
152→                log.debug("Await unblocked: Interrupted while waiting for processable tasks");
153→                return true;
154→            }
155→            log.debug("Await unblocked: Woken up to check for processable tasks");
156→            return false;
157→        });
158→
159→        if (interrupted) {
160→            throw new InterruptedException();
161→        }
162→    }
163→
164→    public void signalTaskExecutors() {
165→        log.debug("Waking up task executors");
166→        executeWithTasksLocked(tasksCondition::signalAll);
167→    }
168→
169→    @Override
170→    public void unassignTask(final StreamTask task, final TaskExecutor executor) {
171→        executeWithTasksLocked(() -> {
172→            if (!taskExecutors.contains(executor)) {
173→                throw new IllegalArgumentException("The requested executor for unassign task is unrecognized");
174→            }
175→
176→            final TaskExecutor lockedExecutor = assignedTasks.get(task.id());
177→            if (lockedExecutor == null || lockedExecutor != executor) {
178→                throw new IllegalArgumentException("Task " + task.id() + " is not locked by the executor");
179→            }
180→
181→            assignedTasks.remove(task.id());
182→
183→            log.debug("Unassigned {} from executor {}", task.id(), executor.name());
184→            tasksCondition.signalAll();
185→        });
186→    }
187→
188→    @Override
189→    public KafkaFuture<Void> lockTasks(final Set<TaskId> taskIds) {
190→        final KafkaFutureImpl<Void> result = new KafkaFutureImpl<>();
191→
192→        if (taskIds.isEmpty()) {
193→            result.complete(null);
194→            return result;
195→        }
196→
197→        return returnWithTasksLocked(() -> {
198→            lockedTasks.addAll(taskIds);
199→
200→            final Set<TaskId> remainingTaskIds = new ConcurrentSkipListSet<>(taskIds);
201→
202→            for (final TaskId taskId : taskIds) {
203→                final Task task = tasks.initializedTask(taskId);
204→
205→                if (task == null) {
206→                    throw new IllegalArgumentException("Trying to lock task " + taskId + " but it's not owned");
207→                }
208→
209→                if (!task.isActive()) {
210→                    throw new IllegalArgumentException("The locking task " + taskId + " is not an active task");
211→                }
212→
213→                if (assignedTasks.containsKey(taskId)) {
214→                    final TaskExecutor executor = assignedTasks.get(taskId);
215→                    log.debug("Requesting release of task {} from {}", taskId, executor.name());
216→                    final KafkaFuture<StreamTask> future = executor.unassign();
217→                    future.whenComplete((streamTask, throwable) -> {
218→                        if (throwable != null) {
219→                            result.completeExceptionally(throwable);
220→                        } else {
221→                            assert !assignedTasks.containsKey(taskId);
222→                            // It can happen that the executor handed back the task before we asked it to
223→                            // in which case `streamTask` will be null here.
224→                            assert streamTask == null || streamTask.id() == taskId;
225→                            remainingTaskIds.remove(taskId);
226→                            if (remainingTaskIds.isEmpty()) {
227→                                result.complete(null);
228→                            }
229→                        }
230→                    });
231→                } else {
232→                    remainingTaskIds.remove(taskId);
233→                    if (remainingTaskIds.isEmpty()) {
234→                        result.complete(null);
235→                    }
236→                }
237→            }
238→
239→            return result;
240→        });
241→    }
242→
243→    @Override
244→    public KafkaFuture<Void> lockAllTasks() {
245→        return returnWithTasksLocked(() ->
246→            lockTasks(tasks.activeInitializedTasks().stream().map(Task::id).collect(Collectors.toSet()))
247→        );
248→    }
249→
250→    @Override
251→    public void unlockTasks(final Set<TaskId> taskIds) {
252→
253→        if (taskIds.isEmpty()) {
254→            return;
255→        }
256→
257→        executeWithTasksLocked(() -> {
258→            lockedTasks.removeAll(taskIds);
259→            log.debug("Waking up task executors");
260→            tasksCondition.signalAll();
261→        });
262→    }
263→
264→    @Override
265→    public void unlockAllTasks() {
266→        executeWithTasksLocked(() -> unlockTasks(tasks.activeInitializedTasks().stream().map(Task::id).collect(Collectors.toSet())));
267→    }
268→
269→    @Override
270→    public void add(final Set<StreamTask> tasksToAdd) {
271→        executeWithTasksLocked(() -> {
272→            for (final StreamTask task : tasksToAdd) {
273→                tasks.addActiveTask(task);
274→            }
275→            log.debug("Waking up task executors");
276→            tasksCondition.signalAll();
277→        });
278→
279→        log.info("Added tasks {} to the task manager to process", tasksToAdd);
280→    }
281→
282→    @Override
283→    public void remove(final TaskId taskId) {
284→        executeWithTasksLocked(() -> {
285→            if (assignedTasks.containsKey(taskId)) {
286→                throw new IllegalArgumentException("The task to remove is still assigned to executors");
287→            }
288→
289→            if (!lockedTasks.contains(taskId)) {
290→                throw new IllegalArgumentException("The task to remove is not locked yet by the task manager");
291→            }
292→
293→            if (!tasks.containsInitialized(taskId)) {
294→                throw new IllegalArgumentException("The task to remove is not owned by the task manager");
295→            }
296→
297→            tasks.removeTask(tasks.initializedTask(taskId));
298→        });
299→
300→        log.info("Removed task {} from the task manager", taskId);
301→    }
302→
303→    @Override
304→    public Set<ReadOnlyTask> getTasks() {
305→        return returnWithTasksLocked(() -> tasks.activeInitializedTasks().stream().map(ReadOnlyTask::new).collect(Collectors.toSet()));
306→    }
307→
308→    @Override
309→    public void setUncaughtException(final StreamsException exception, final TaskId taskId) {
310→        executeWithTasksLocked(() -> {
311→
312→            if (!assignedTasks.containsKey(taskId)) {
313→                throw new IllegalArgumentException("An uncaught exception can only be set as long as the task is still assigned");
314→            }
315→
316→            if (uncaughtExceptions.containsKey(taskId)) {
317→                throw new IllegalArgumentException("The uncaught exception must be cleared before restarting processing");
318→            }
319→
320→            uncaughtExceptions.put(taskId, exception);
321→        });
322→
323→        log.info("Set an uncaught exception of type {} for task {}, with error message: {}",
324→            exception.getClass().getName(),
325→            taskId,
326→            exception.getMessage());
327→    }
328→
329→    public Map<TaskId, RuntimeException> drainUncaughtExceptions() {
330→        final Map<TaskId, RuntimeException> returnValue = returnWithTasksLocked(() -> {
331→            final Map<TaskId, RuntimeException> result = new HashMap<>(uncaughtExceptions);
332→            uncaughtExceptions.clear();
333→            return result;
334→        });
335→
336→        if (!returnValue.isEmpty()) {
337→            log.debug("Drained {} uncaught exceptions", returnValue.size());
338→        }
339→
340→        return returnValue;
341→    }
342→
343→    public boolean hasUncaughtException(final TaskId taskId) {
344→        return returnWithTasksLocked(() -> uncaughtExceptions.containsKey(taskId));
345→    }
346→
347→    private void executeWithTasksLocked(final Runnable action) {
348→        tasksLock.lock();
349→        try {
350→            action.run();
351→        } finally {
352→            tasksLock.unlock();
353→        }
354→    }
355→
356→    private <T> T returnWithTasksLocked(final Supplier<T> action) {
357→        tasksLock.lock();
358→        try {
359→            return action.get();
360→        } finally {
361→            tasksLock.unlock();
362→        }
363→    }
364→
365→    private boolean canProgress(final StreamTask task, final long nowMs) {
366→        return
367→            taskExecutionMetadata.canProcessTask(task, nowMs) && task.isProcessable(nowMs) ||
368→                taskExecutionMetadata.canPunctuateTask(task) && (task.canPunctuateStreamTime() || task.canPunctuateSystemTime());
369→    }
370→
371→    public void startTaskExecutors() {
372→        for (final TaskExecutor t: taskExecutors) {
373→            t.start();
374→        }
375→    }
376→
377→    public void shutdown(final Duration duration) {
378→        for (final TaskExecutor t: taskExecutors) {
379→            t.requestShutdown();
380→        }
381→        signalTaskExecutors();
382→        for (final TaskExecutor t: taskExecutors) {
383→            t.awaitShutdown(duration);
384→        }
385→    }
386→}
