 83→/**
 84→ * Manages the directories where the state of Tasks owned by a {@link StreamThread} are
 85→ * stored. Handles creation/locking/unlocking/cleaning of the Task Directories. This class is not
 86→ * thread-safe.
 87→ */
 88→public class StateDirectory implements AutoCloseable {
 89→
 90→    private static final Pattern TASK_DIR_PATH_NAME = Pattern.compile("\\d+_\\d+");
 91→    private static final Pattern NAMED_TOPOLOGY_DIR_PATH_NAME = Pattern.compile("__.+__"); // named topology dirs follow '__Topology-Name__'
 92→    private static final Logger log = LoggerFactory.getLogger(StateDirectory.class);
 93→    static final String LOCK_FILE_NAME = ".lock";
 94→
 95→    /* The process file is used to persist the process id across restarts.
 96→     * For compatibility reasons you should only ever add fields to the json schema
 97→     */
 98→    static final String PROCESS_FILE_NAME = "kafka-streams-process-metadata";
 99→
100→    @JsonIgnoreProperties(ignoreUnknown = true)
101→    static class StateDirectoryProcessFile {
102→        @JsonProperty
103→        private final UUID processId;
104→
105→        // required by jackson -- do not remove, your IDE may be warning that this is unused but it's lying to you
106→        public StateDirectoryProcessFile() {
107→            this.processId = null;
108→        }
109→
110→        StateDirectoryProcessFile(final UUID processId) {
111→            this.processId = processId;
112→        }
113→    }
114→
115→    private final Object taskDirCreationLock = new Object();
116→    private final Time time;
117→    private final String appId;
118→    private final File stateDir;
119→    private final boolean hasPersistentStores;
120→    private final boolean hasNamedTopologies;
121→
122→    private final ConcurrentMap<TaskId, Thread> lockedTasksToOwner = new ConcurrentHashMap<>();
123→
124→    private FileChannel stateDirLockChannel;
125→    private FileLock stateDirLock;
126→
127→    private final StreamsConfig config;
128→    private final Set<TaskId> tasksInLocalState = new ConcurrentSkipListSet<>();
129→    private final Map<TaskId, Long> taskOffsetSums = new ConcurrentHashMap<>();
130→
131→    /**
132→     * Ensures that the state base directory as well as the application's sub-directory are created.
133→     *
134→     * @param config              streams application configuration to read the root state directory path
135→     * @param time                system timer used to execute periodic cleanup procedure
136→     * @param hasPersistentStores only when the application's topology does have stores persisted on local file
137→     *                            system, we would go ahead and auto-create the corresponding application / task / store
138→     *                            directories whenever necessary; otherwise no directories would be created.
139→     * @param hasNamedTopologies  whether this application is composed of independent named topologies
140→     *
141→     * @throws ProcessorStateException if the base state directory or application state directory does not exist
142→     *                                 and could not be created when hasPersistentStores is enabled.
143→     */
144→    public StateDirectory(final StreamsConfig config, final Time time, final boolean hasPersistentStores, final boolean hasNamedTopologies) {
145→        this.time = time;
146→        this.hasPersistentStores = hasPersistentStores;
147→        this.hasNamedTopologies = hasNamedTopologies;
148→        this.appId = config.getString(StreamsConfig.APPLICATION_ID_CONFIG);
149→        this.config = config;
150→        final String stateDirName = config.getString(StreamsConfig.STATE_DIR_CONFIG);
151→        final File baseDir = new File(stateDirName);
152→        stateDir = new File(baseDir, appId);
153→
154→        if (this.hasPersistentStores) {
155→            if (!baseDir.exists() && !baseDir.mkdirs()) {
156→                throw new ProcessorStateException(
157→                    String.format("base state directory [%s] doesn't exist and couldn't be created", stateDirName));
158→            }
159→            if (!stateDir.exists() && !stateDir.mkdir()) {
160→                throw new ProcessorStateException(
161→                    String.format("state directory [%s] doesn't exist and couldn't be created", stateDir.getPath()));
162→            } else if (stateDir.exists() && !stateDir.isDirectory()) {
163→                throw new ProcessorStateException(
164→                    String.format("state directory [%s] can't be created as there is an existing file with the same name", stateDir.getPath()));
165→            }
166→
167→            if (stateDirName.startsWith(System.getProperty("java.io.tmpdir"))) {
168→                log.warn("Using an OS temp directory in the state.dir property can cause failures with writing" +
169→                    " the checkpoint file due to the fact that this directory can be cleared by the OS." +
170→                    " Resolved state.dir: [" + stateDirName + "]");
171→
172→            }
173→            // change the dir permission to "rwxr-x---" to avoid world readable
174→            configurePermissions(baseDir);
175→            configurePermissions(stateDir);
176→        }
177→    }
178→
179→    private void configurePermissions(final File file) {
180→        final Path path = file.toPath();
181→        if (path.getFileSystem().supportedFileAttributeViews().contains("posix")) {
182→            final Set<PosixFilePermission> perms = EnumSet.of(
183→                    PosixFilePermission.OWNER_READ,
184→                    PosixFilePermission.OWNER_WRITE,
185→                    PosixFilePermission.OWNER_EXECUTE,
186→                    PosixFilePermission.GROUP_READ,
187→                    PosixFilePermission.GROUP_EXECUTE
188→            );
189→            if (config.getBoolean(StreamsConfig.ALLOW_OS_GROUP_WRITE_ACCESS_CONFIG)) {
190→                perms.add(PosixFilePermission.GROUP_WRITE);
191→            }
192→            try {
193→                Files.setPosixFilePermissions(path, perms);
194→            } catch (final IOException e) {
195→                log.error("Error changing permissions for the directory {} ", path, e);
196→            }
197→        } else {
198→            boolean set = file.setReadable(true, true);
199→            set &= file.setWritable(true, true);
200→            set &= file.setExecutable(true, true);
201→            if (!set) {
202→                log.error("Failed to change permissions for the directory {}", file);
203→            }
204→        }
205→    }
206→
207→    /**
208→     * @return true if the state directory was successfully locked
209→     */
210→    private boolean lockStateDirectory() {
211→        final File lockFile = new File(stateDir, LOCK_FILE_NAME);
212→        try {
213→            stateDirLockChannel = FileChannel.open(lockFile.toPath(), StandardOpenOption.CREATE, StandardOpenOption.WRITE);
214→            stateDirLock = tryLock(stateDirLockChannel);
215→        } catch (final IOException e) {
216→            log.error("Unable to lock the state directory due to unexpected exception", e);
217→            throw new ProcessorStateException(String.format("Failed to lock the state directory [%s] during startup",
218→                stateDir.getAbsolutePath()), e);
219→        }
220→        return stateDirLock != null;
221→    }
