223→    /**
224→     * @throws LockException If another process already locks any of StateDirectory
225→     * @throws ProcessorStateException if any of task directory does not exist and could not be created
226→    */
227→    public void initializeStartupStores(final TopologyMetadata topologyMetadata,
228→                                        final LogContext logContext,
229→                                        final StreamsMetricsImpl metricsImpl) {
230→        final List<TaskDirectory> nonEmptyTaskDirectories = listNonEmptyTaskDirectories();
231→        if (hasPersistentStores && !nonEmptyTaskDirectories.isEmpty()) {
232→            final boolean eosEnabled = StreamsConfigUtils.eosEnabled(config);
233→
234→            // Initialize thread-specific resources needed to open stores in the state directory
235→            final String threadLogPrefix = String.format("[%s]", Thread.currentThread().getName());
236→            final ThreadCache dummyCache = new ThreadCache(new LogContext(threadLogPrefix), 0L, metricsImpl);
237→
238→            // discover all non-empty task directories in StateDirectory
239→            for (final TaskDirectory taskDirectory : nonEmptyTaskDirectories) {
240→                final String dirName = taskDirectory.file().getName();
241→                final TaskId task = parseTaskDirectoryName(dirName, taskDirectory.namedTopology());
242→                final ProcessorTopology subTopology = topologyMetadata.buildSubtopology(task);
243→
244→                // we still check if the task's sub-topology is stateful, even though we know its directory contains state,
245→                // because it's possible that the topology has changed since that data was written, and is now stateless
246→                // this therefore prevents us from creating unnecessary stores just because of some left-over state
247→                if (subTopology.hasStateWithChangelogs()) {
248→                    final Set<TopicPartition> inputPartitions = topologyMetadata.nodeToSourceTopics(task).values().stream()
249→                            .flatMap(Collection::stream)
250→                            .map(t -> new TopicPartition(t, task.partition()))
251→                            .collect(Collectors.toSet());
252→                    // Open a temporary state manager that will open the stores inside the subtopology
253→                    final ProcessorStateManager temporaryStateManager = ProcessorStateManager.createStartupTaskStateManager(
254→                        task,
255→                        eosEnabled,
256→                        logContext,
257→                        this,
258→                        subTopology.storeToChangelogTopic(),
259→                        inputPartitions
260→                    );
261→
262→                    final StartupContext initContext = new StartupContext(task, config, temporaryStateManager, metricsImpl, dummyCache);
263→                    try {
264→                        // We only handle TaskCorruptedException at this point. Any other exception is considered fatal.
265→                        StateManagerUtil.registerStateStores(log, threadLogPrefix, subTopology, temporaryStateManager, this, initContext);
266→                        temporaryStateManager.checkpoint();
267→                    } catch (final TaskCorruptedException tce) {
268→                        // At this point, we only log a warning and continue with the startup store initialization.
269→                        // The task-corrupted exception will be handled in the first Task assignment phase.
270→                        log.warn("Failed to register startup state stores for task {}: {}", task, tce.getMessage());
271→                    } finally {
272→                        // Make sure the state manager writes the local checkpoint file before closing the stores
273→                        // This will be replaced in the future when removing the checkpoint file dependency.
274→                        temporaryStateManager.close();
275→                    }
276→                    tasksInLocalState.add(task);
277→                }
278→            }
279→        }
280→    }
