307→    public void updateTaskOffsets(final TaskId taskId, final Map<TopicPartition, Long> changelogOffsets) {
308→        if (!changelogOffsets.isEmpty()) {
309→            taskOffsetSums.put(taskId, sumOfChangelogOffsets(taskId, changelogOffsets));
310→        }
