380→    /**
381→     * Get or create the directory for the provided {@link TaskId}.
382→     * @return directory for the {@link TaskId}
383→     * @throws ProcessorStateException if the task directory does not exist and could not be created
384→     */
385→    public File getOrCreateDirectoryForTask(final TaskId taskId) {
386→        final File taskParentDir = getTaskDirectoryParentName(taskId);
387→        final File taskDir = new File(taskParentDir, StateManagerUtil.toTaskDirString(taskId));
388→        if (hasPersistentStores) {
389→            if (!taskDir.exists()) {
390→                synchronized (taskDirCreationLock) {
391→                    // to avoid a race condition, we need to check again if the directory does not exist:
392→                    // otherwise, two threads might pass the outer `if` (and enter the `then` block),
393→                    // one blocks on `synchronized` while the other creates the directory,
394→                    // and the blocking one fails when trying to create it after it's unblocked
395→                    if (!taskParentDir.exists() && !taskParentDir.mkdir()) {
396→                        throw new ProcessorStateException(
397→                            String.format("Parent [%s] of task directory [%s] doesn't exist and couldn't be created",
398→                                taskParentDir.getPath(), taskDir.getPath()));
399→                    }
400→                    if (!taskDir.exists() && !taskDir.mkdir()) {
401→                        throw new ProcessorStateException(
402→                            String.format("task directory [%s] doesn't exist and couldn't be created", taskDir.getPath()));
403→                    }
404→                }
405→            } else if (!taskDir.isDirectory()) {
406→                throw new ProcessorStateException(
407→                    String.format("state directory [%s] can't be created as there is an existing file with the same name", taskDir.getPath()));
408→            }
409→        }
410→        return taskDir;
411→    }
