542→    @Override
543→    public void close() {
544→        if (hasPersistentStores) {
545→            unlockStartupStores();
546→            taskOffsetSums.clear();
547→            try {
548→                stateDirLock.release();
549→                stateDirLockChannel.close();
550→
551→                stateDirLock = null;
552→                stateDirLockChannel = null;
553→            } catch (final IOException e) {
554→                log.error("Unexpected exception while unlocking the state dir", e);
555→                throw new StreamsException(String.format("Failed to release the lock on the state directory [%s]", stateDir.getAbsolutePath()), e);
556→            }
557→
558→            // all threads should be stopped and cleaned up by now, so none should remain holding a lock
559→            if (!lockedTasksToOwner.isEmpty()) {
560→                log.error("Some task directories still locked while closing state, this indicates unclean shutdown: {}", lockedTasksToOwner);
561→            }
562→        }
563→    }
