151→        private boolean processTask(final Task task, final long now, final Time time) {
152→            boolean processed = false;
153→            try {
154→                processed = task.process(now);
155→                if (processed) {
156→                    log.trace("Successfully processed task {}", task.id());
157→                    task.clearTaskTimeout();
158→                    // TODO: enable regardless of whether using named topologies
159→                    if (taskExecutionMetadata.hasNamedTopologies() && taskExecutionMetadata.processingMode() != EXACTLY_ONCE_V2) {
160→                        taskExecutionMetadata.addToSuccessfullyProcessed(task);
161→                    }
162→                }
163→            } catch (final TimeoutException timeoutException) {
164→                // TODO consolidate TimeoutException retries with general error handling
165→                task.maybeInitTaskTimeoutOrThrow(now, timeoutException);
166→                log.error(
167→                    String.format(
168→                        "Could not complete processing records for %s due to the following exception; will move to next task and retry later",
169→                        task.id()),
170→                    timeoutException
171→                );
172→            } catch (final TaskMigratedException e) {
173→                log.info("Failed to process stream task {} since it got migrated to another thread already. " +
174→                    "Will trigger a new rebalance and close all tasks as zombies together.", task.id());
175→                throw e;
176→            } catch (final StreamsException e) {
177→                log.error(String.format("Failed to process stream task %s due to the following error:", task.id()), e);
178→                e.setTaskId(task.id());
179→                throw e;
180→            } catch (final RuntimeException e) {
181→                log.error(String.format("Failed to process stream task %s due to the following error:", task.id()), e);
182→                throw new StreamsException(e, task.id());
183→            } finally {
184→                task.recordProcessBatchTime(time.milliseconds() - now);
185→            }
186→            return processed;
187→        }
188→
189→        private StreamTask unassignCurrentTask() {
190→            if (currentTask == null)
191→                throw new IllegalStateException("Does not own any task while being ask to unassign from task manager");
192→
193→            // flush the task before giving it back to task manager, if we are not handing it back because of an error.
194→            if (!taskManager.hasUncaughtException(currentTask.id())) {
195→                try {
196→                    currentTask.flush();
197→                } catch (final StreamsException e) {
198→                    log.error(String.format("Failed to flush stream task %s due to the following error:", currentTask.id()), e);
199→                    e.setTaskId(currentTask.id());
200→                    taskManager.setUncaughtException(e, currentTask.id());
201→                } catch (final RuntimeException e) {
202→                    log.error(String.format("Failed to flush stream task %s due to the following error:", currentTask.id()), e);
203→                    taskManager.setUncaughtException(new StreamsException(e, currentTask.id()), currentTask.id());
204→                }
205→            }
206→            taskManager.unassignTask(currentTask, DefaultTaskExecutor.this);
207→
208→            final StreamTask retTask = currentTask;
209→            currentTask = null;
210→            return retTask;
211→        }
212→    }
