260→    @Override
261→    public void awaitShutdown(final Duration timeout) {
262→        if (taskExecutorThread != null) {
263→            try {
264→                taskExecutorThread.join(timeout.toMillis());
265→                if (taskExecutorThread.isAlive()) {
266→                    throw new StreamsException("State updater thread did not shutdown within the timeout");
267→                }
268→                taskExecutorThread = null;
269→            } catch (final InterruptedException ignored) {
270→            }
271→        }
